local settings = {}

BowConfig = {}

function BowConfig:init(config)
    for _, item in pairs(config) do
        settings[item.bowId] = {
            arrowId = tonumber(item.arrowId),
            arrowNum = tonumber(item.arrowNum)
        }
    end
end

function BowConfig:getBowConfig(bowId)
    return settings[tostring(bowId)]
end
